    <text x="110" y="182" fill="#a1a1aa" font-size="12">Exercice fiscal clos en mars 2023</text>

    <rect x="180" y="222" width="310" height="54" rx="8" fill="#1c1c1f" stroke="#fb7185" stroke-width="1.5"/>
    <text x="200" y="244" fill="#fb7185" font-size="14" font-weight="700">Déclaré aux impôts</text>
    <text x="470" y="244" fill="#fafafa" font-size="16" font-weight="700" text-anchor="end">Moins d'1 sur 4</text>
    <text x="200" y="264" fill="#a1a1aa" font-size="12">Le reste échappe au fisc</text>

    <line x1="340" y1="112" x2="340" y2="138" stroke="#71717a" stroke-width="2" marker-end="url(#arG1f)"/>
